  const response = await this.request(
    `/accounts/${this.accountId}/workers/scripts/${this.projectName}/deployments/${providerDeploymentId}`
  );

  if (response.status === 404) {
    return {
      status: 'running',
      deployedUrl: null,
    };
  }

